{-# LANGUAGE OverloadedStrings #-}
module GenerationSpec where
import qualified Data.ByteString as BS
import Test.Hspec

import Blockchain.Data.GenesisInfo
import Blockchain.Generation
import Blockchain.Strato.Model.Address
import Blockchain.Strato.Model.SHA

start :: GenesisInfo
start = defaultGenesisInfo

emptyContractB16 :: BS.ByteString
emptyContractB16 = "60606040525b600080fd00a165627a7a723058209b97b86115f9dfccb5f10ab93044730e948264e405825b26dccd1605775663710029"

emptyContract :: BS.ByteString
emptyContract = "```@R[`\NUL\128\253\NUL\161ebzzr0X \155\151\184a\NAK\249\223\204\181\241\n\185\&0Ds\SO\148\130d\228\ENQ\130[&\220\205\SYN\ENQwVcq\NUL)"

vehicleContractB16 :: BS.ByteString
vehicleContractB16 = ""


emptyHash :: SHA
-- emptyHash = SHA 0x6ee829aad0ec74494a6cf1433f563bbbe7e556a2a067d6ecd596dda0aecd8202
-- emptyHash = SHA 0x134af24a6b310178f9d219577365a20176f874c40314468d87e663d1d56b3d4f
emptyHash = SHA 0xc4295782f7f9af2134f7beb6b68eedcd32a5a44f8fbcc68d87e663d1d56b3d4f

vehicleHash :: SHA
vehicleHash = SHA 0x7e24eb3319d8b055c7a27509a1abee64fed1b7acb070accf6a6764a11915c915

sharedStart :: Address
sharedStart = Address 0x692a70d2e424a56d2c6c27aa97d1a86395877b3a

spec :: Spec
spec = do
  describe "Insertion of empty contracts" $ do
    it "should insert no contracts" $
      let input = defaultGenesisInfo
          want = []
          got = insertContracts emptyContractB16 sharedStart 0 input
      in genesisInfoAccountInfo got `shouldBe` want

    it "should insert 1 contract" $
      let input = defaultGenesisInfo
          want = [Contract sharedStart 0 emptyHash]
          got = insertContracts emptyContractB16 sharedStart 1 input
      in genesisInfoAccountInfo got `shouldBe` want

    it "should insert 1m contracts" $
      let total = 1000000 :: Integer
          input = defaultGenesisInfo
          want = map (\n -> Contract (sharedStart + fromIntegral n) 0 emptyHash) [0..total-1]
          got = insertContracts emptyContractB16 sharedStart total input
      in genesisInfoAccountInfo got `shouldBe` want

    it "should add emptyContract to the contractInfo" $
      let input = defaultGenesisInfo
          want = [emptyContract]
          got = insertContracts emptyContractB16 sharedStart 10 input
      in genesisInfoCodeInfo got `shouldBe` want

    it "should have the right vehicle hash" $
      let input = defaultGenesisInfo
          want = [vehicleHash]
          got = map superProprietaryStratoSHAHash .
                genesisInfoCodeInfo .
                insertContracts vehicleContractB16 sharedStart 10 $ input
      in got `shouldBe` want
